mapper.select:
select t1.* , t2.chart_data , t2.chart_nm , count(t3.*) as registCnt from esg.tb_emergency_control_task_asgmt t1 left join esg.tb_emergency_control_org_chart t2 on t1.chart_id = t2.chart_id and t1.comp_id = t2.comp_id left join esg.tb_emergency_control_task_asgmt_detail t3 on t1.write_year = t3.write_year and t1.doc_type = t3.doc_type and t1.doc_no = t3.doc_no and t1.comp_id = t3.comp_id where t1.comp_id = #{compId}
and t1.write_year = #{writeYear} and t1.doc_type = #{docType} and t1.doc_no = #{docNo}
group by t1.write_year, t1.doc_type, t1.doc_no, t1.chart_id,t2.chart_data ,t2.chart_nm order by t1.write_year desc, t1.use_yn desc, t1.write_dt desc

select t1.*
from esg.tb_emergency_control_task_asgmt_detail t1
where t1.comp_id = #{compId}
    and t1.write_year = #{writeYear}
    and t1.doc_type = #{docType}
    and t1.doc_no = #{docNo}
order by t1.role_id desc

select t1.*
    , t2.hr_nm
from esg.tb_emergency_control_task_asgmt_detail_hr t1
left join esg.tb_hr_info t2
    on t1.hr_id = t2.hr_id
where t1.comp_id = #{compId}
    and t1.write_year = #{writeYear}
    and t1.doc_type = #{docType}
    and t1.doc_no = #{docNo}
    and t1.role_id = #{roleId}

